import api from '../../Api/api';
import { ApiStandardUser } from '../../Api/config';
import createNotification from 'src/components/Handle.Error/notifications';

// GET /api/general-info
const getGeneralInfo = async () => {
  try {
    const result = await api.get(ApiStandardUser.api_GeneralInfo);
    return result.data.error
      ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error))
      : result.data;
  } catch (error) {
    createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));
    return null;
  }
};

// PUT /api/general-info
const updateGeneralInfo = async (data) => {
  try {
    const result = await api.put(ApiStandardUser.api_GeneralInfo, data);
    return result.data.error
      ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error))
      : result.data;
  } catch (error) {
    createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));
    return null;
  }
};

const generalInfoService = {
  get: getGeneralInfo,
  update: updateGeneralInfo,
};

export default generalInfoService;
