import React, { useState, useEffect, useCallback } from 'react';
import {
  CButton, CModal, CModalHeader, CModalTitle, CModalBody, CModalFooter,
  CForm, CCol, CFormLabel, CFormFeedback, CFormInput, CFormSelect, CFormTextarea
} from '@coreui/react';
import CIcon from '@coreui/icons-react';
import { cilPen, cilPlus } from '@coreui/icons';
import PropTypes from 'prop-types';
import i18n from 'src/i18n';
import { settingsAppointments } from 'src/services/standardUsers';
import { settingsConfigs } from 'src/services/SupperSettings';
import createNotification from 'src/components/Handle.Error/notifications';

const initialAppointmentState = {
  client_code: '',
  client_name: '',
  client_contact: '',
  date: '',
  time: '',
  duration: 30,
  hardware: '',
  software: '',
  meeting_reason: '',
  description: '',
};

const AppointmentsC = ({ refresh, selectedAppointments }) => {
  const isEdit = !!selectedAppointments?.id;
  const [visible, setVisible] = useState(false);
  const [validated, setValidated] = useState(false);
  const [appointment, setAppointment] = useState(initialAppointmentState);
  const [customers, setCustomers] = useState([]);
  const [listMotifs, setListMotifs] = useState([]);

  const fetchMotifs = useCallback(async () => {
    try {
      const response = await settingsConfigs.getConfig("motifs");
      setListMotifs(response?.data || []);
    } catch (error) {
      console.error("Error fetching motifs:", error);
    }
  }, []);

  const fetchCustomers = useCallback(async () => {
    try {
      const response = await settingsConfigs.getConfig("customers");
      setCustomers(response?.data || []);
    } catch (err) {
      console.error("Failed to fetch customers", err);
    }
  }, []);

  const openModal = async () => {
    await Promise.all([fetchMotifs(), fetchCustomers()]);
    setVisible(true);
  };

  useEffect(() => {
    setAppointment(selectedAppointments || initialAppointmentState);
  }, [selectedAppointments]);

  const handleChange = (field) => (e) => {
    setAppointment((prev) => ({ ...prev, [field]: e.target.value }));
  };

  const selectListCustomers = (attribute, value) => {
    const customer = customers.find(cust => cust[attribute] === value);
    if (customer) {
      setAppointment((prev) => ({
        ...prev,
        customerId: customer.id,
        client_code: customer.code || '',
        client_name: customer.username || '',
        client_contact: customer.phone_number || '',
      }));
    } else {
      alert(i18n.t('customerNotFound'));
      setAppointment((prev) => ({
        ...prev,
        customerId: '',
        client_code: '',
        client_name: '',
        client_contact: '',
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setValidated(true);

    if (!e.currentTarget.checkValidity()) return;

    let result;
    if (selectedAppointments?.id) {
      result = await settingsAppointments.updateAppointments(selectedAppointments.id, appointment);
    } else {
      result = await settingsAppointments.addAppointments(appointment, 'entity/appointment');
    }

    if (result) {
      createNotification("success");
      setVisible(false);
      setValidated(false);
      setAppointment(initialAppointmentState);
      refresh();
    }
  };
  return (
    <>
      <CButton color= {isEdit ? "secondray" : "primary"} onClick={openModal}>
        <CIcon icon={isEdit ? cilPen :  cilPlus} /> 
       {!isEdit && i18n.t('addAppointmentTitle')}
      </CButton>

      <CModal alignment="center" visible={visible} onClose={() => setVisible(false)}>
        <CModalHeader onClose={() => setVisible(false)}>
          {isEdit ? i18n.t('updateAppointmentTitle') : i18n.t('addAppointmentTitle')}
        </CModalHeader>
        <CModalBody>
          <CForm className="row g-3 needs-validation" noValidate validated={validated} onSubmit={handleSubmit}>
            <CCol md={3}><CFormLabel>{i18n.t('clientCode')}</CFormLabel></CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_code} onChange={handleChange('client_code')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3} className="d-flex align-items-end">
              <CButton color="primary" className="w-100" onClick={() => selectListCustomers('code', appointment.client_code)}>
                {i18n.t('search')}
              </CButton>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('clientName')}</CFormLabel></CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_name} onChange={handleChange('client_name')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3} className="d-flex align-items-end">
              <CButton color="primary" className="w-100" onClick={() => selectListCustomers('username', appointment.client_name)}>
                {i18n.t('search')}
              </CButton>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('clientContact')}</CFormLabel></CCol>
            <CCol md={6}>
              <CFormInput value={appointment.client_contact} onChange={handleChange('client_contact')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>
            <CCol md={3} className="d-flex align-items-end">
              <CButton color="primary" className="w-100" onClick={() => selectListCustomers('phone_number', appointment.client_contact)}>
                {i18n.t('search')}
              </CButton>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('date')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormInput type="date" value={appointment.date} onChange={handleChange('date')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('time')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormInput type="time" value={appointment.time} onChange={handleChange('time')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('duration')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormInput type="number" value={appointment.duration} onChange={handleChange('duration')} required />
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('hardware')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.hardware} onChange={handleChange('hardware')} required>
                <option value="">{i18n.t('selectOption')}</option>
                {listMotifs.filter(m => m.type === 'hw').map((item, i) => (
                  <option key={i} value={item.name}>{item.name}</option>
                ))}
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('software')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.software} onChange={handleChange('software')} required>
                <option value="">{i18n.t('selectOption')}</option>
                {listMotifs.filter(m => m.type === 'sw').map((item, i) => (
                  <option key={i} value={item.name}>{item.name}</option>
                ))}
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={3}><CFormLabel>{i18n.t('meetingReason')}</CFormLabel></CCol>
            <CCol md={9}>
              <CFormSelect value={appointment.meeting_reason} onChange={handleChange('meeting_reason')} required>
                <option value="">{i18n.t('selectOption')}</option>
                {listMotifs.filter(m => m.type === 'motif').map((item, i) => (
                  <option key={i} value={item.name}>{item.name}</option>
                ))}
              </CFormSelect>
              <CFormFeedback invalid>{i18n.t('requiredField')}</CFormFeedback>
            </CCol>

            <CCol md={12}>
              <CFormLabel>{i18n.t('description')}</CFormLabel>
              <CFormTextarea rows={4} value={appointment.description} onChange={handleChange('description')} />
            </CCol>

            <CModalFooter>
              <CButton color="secondary" onClick={() => setVisible(false)}>{i18n.t('closeButton')}</CButton>
              <CButton color="primary" type="submit">{i18n.t('saveButton')}</CButton>
            </CModalFooter>
          </CForm>
        </CModalBody>
      </CModal>
    </>
  );
};

AppointmentsC.propTypes = {
  refresh: PropTypes.func.isRequired,
  selectedAppointments: PropTypes.object,
};

export default AppointmentsC;
