

import api from '../../Api/api';
import createNotification from 'src/components/Handle.Error/notifications';
import { ApiSupperSettings } from '../../Api/config';


const getConfig = async (entity) => {
    try {
        const result = await api.get(ApiSupperSettings.api_ConfigApps + entity);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));
        return null;
    }
};
const addConfig = async (data, entity) => {
    try {
        console.log("ApiSupperSettings.api_ConfigApps + entity")
        const result = await api.post(ApiSupperSettings.api_ConfigApps + entity, data);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));
        return null;
    }
};
const updateConfig = async (data, id, entity) => {
    try {
        console.log(ApiSupperSettings.api_ConfigApps +entity +"/"+id, data)
        console.log(data, id, entity)
        const result = await api.put(ApiSupperSettings.api_ConfigApps +entity +"/"+id, data);
        return result.data.error ? createNotification("error", JSON.stringify(result?.data?.error), JSON.stringify(result?.data?.error)) : result.data;
    } catch (error) {
        createNotification("error", JSON.stringify(error?.response?.data), JSON.stringify(error?.response?.data));
        return null;
    }
};



const ConfigFun = {
    getConfig,
    addConfig,
    updateConfig,
};

export default ConfigFun;


